const llmResponse = $input.item.json.message.content.trim();
const trigger = $('Execute Workflow Trigger').first().json;

let parsed;
try {
  parsed = JSON.parse(llmResponse);
} catch (e) {
  parsed = { error: 'NEEDS_INPUT' };
}

return {
  json: {
    parsed_date: parsed.date || null,
    parsed_time: parsed.time || null,
    has_error: !!(parsed.error),
    booking_context: trigger.booking_context,
    patient_id: trigger.patient_id,
    patient_name: trigger.patient_name,
    wa_contact_id: trigger.wa_contact_id,
    remote_jid: trigger.remote_jid,
    instance_name: trigger.instance_name,
    api_key: trigger.api_key
  }
};

const items = $input.all();
const datetimeNode = $('Parse Date Time from LLM').first().json;
const trigger = $('Execute Workflow Trigger').first().json;

const targetDate = datetimeNode.parsed_date;
const targetTime = datetimeNode.parsed_time || '10:00';

// Build list of busy periods from calendar events
const busySlots = items
  .filter(item => item.json.start)
  .map(item => ({
    start: new Date(item.json.start.dateTime || item.json.start.date + 'T00:00:00').getTime(),
    end: new Date(item.json.end.dateTime || item.json.end.date + 'T23:59:00').getTime()
  }));

// Generate 30-minute slots from 9:00 to 17:30
const slots = [];
const workStart = 9 * 60; // minutes from midnight
const workEnd = 17 * 60 + 30;
const slotDuration = 30;

for (let m = workStart; m + slotDuration <= workEnd + slotDuration; m += slotDuration) {
  const slotStartHour = Math.floor(m / 60);
  const slotStartMin = m % 60;
  const slotEndMin = m + slotDuration;
  const slotEndHour = Math.floor(slotEndMin / 60);
  const slotEndMinute = slotEndMin % 60;

  const startStr = targetDate + 'T' + String(slotStartHour).padStart(2,'0') + ':' + String(slotStartMin).padStart(2,'0') + ':00';
  const endStr = targetDate + 'T' + String(slotEndHour).padStart(2,'0') + ':' + String(slotEndMinute).padStart(2,'0') + ':00';

  const slotStartMs = new Date(startStr).getTime();
  const slotEndMs = new Date(endStr).getTime();

  // Check not overlapping with any busy slot
  const isFree = !busySlots.some(busy => slotStartMs < busy.end && slotEndMs > busy.start);
  if (isFree) {
    slots.push({ start: startStr, end: endStr });
  }
}

// Sort slots by proximity to preferred time
const [prefHour, prefMin] = (targetTime || '10:00').split(':').map(Number);
const prefMinutes = prefHour * 60 + (prefMin || 0);
slots.sort((a, b) => {
  const aMinutes = parseInt(a.start.split('T')[1].split(':')[0]) * 60 + parseInt(a.start.split('T')[1].split(':')[1]);
  const bMinutes = parseInt(b.start.split('T')[1].split(':')[0]) * 60 + parseInt(b.start.split('T')[1].split(':')[1]);
  return Math.abs(aMinutes - prefMinutes) - Math.abs(bMinutes - prefMinutes);
});

const topSlots = slots.slice(0, 3);

// Format slots for display
const formatSlot = (s) => {
  const parts = s.start.split('T');
  const timeParts = parts[1].split(':');
  const dateParts = parts[0].split('-');
  return `${dateParts[2]}/${dateParts[1]}/${dateParts[0]} a las ${timeParts[0]}:${timeParts[1]}`;
};

return [{
  json: {
    available_slots: topSlots,
    slots_found: topSlots.length > 0,
    target_date: targetDate,
    slot_1: topSlots[0] ? formatSlot(topSlots[0]) : null,
    slot_2: topSlots[1] ? formatSlot(topSlots[1]) : null,
    slot_3: topSlots[2] ? formatSlot(topSlots[2]) : null,
    booking_context: datetimeNode.booking_context,
    patient_id: datetimeNode.patient_id,
    patient_name: datetimeNode.patient_name,
    wa_contact_id: datetimeNode.wa_contact_id,
    remote_jid: datetimeNode.remote_jid,
    instance_name: datetimeNode.instance_name,
    api_key: datetimeNode.api_key
  }
}];

const trigger = $('Execute Workflow Trigger').first().json;
const messageText = trigger.message_text || '';
const bookingContext = trigger.booking_context || {};
const availableSlots = bookingContext.available_slots || [];

// Parse selection: look for digit 1, 2, or 3
const match = messageText.match(/[123]/);
const selectionIndex = match ? parseInt(match[0]) - 1 : -1;

const selectedSlot = (selectionIndex >= 0 && selectionIndex < availableSlots.length)
  ? availableSlots[selectionIndex]
  : null;

return {
  json: {
    valid_selection: selectedSlot !== null,
    selected_slot: selectedSlot,
    service_type: bookingContext.service_type || 'Consulta general',
    patient_id: trigger.patient_id,
    patient_name: bookingContext.patient_name || trigger.patient_name || 'Paciente',
    wa_contact_id: trigger.wa_contact_id,
    remote_jid: trigger.remote_jid,
    instance_name: trigger.instance_name,
    api_key: trigger.api_key
  }
};

const slotSelection = $('Parse Slot Selection').first().json;
const selectedSlot = slotSelection.selected_slot;

// Format date for Spanish display
const slotStart = new Date(selectedSlot.start);
const day = String(slotStart.getDate()).padStart(2, '0');
const monthNames = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
const month = monthNames[slotStart.getMonth()];
const year = slotStart.getFullYear();
const hours = String(slotStart.getHours()).padStart(2, '0');
const minutes = String(slotStart.getMinutes()).padStart(2, '0');

const fechaFormatted = `${day} de ${month} de ${year}`;
const horaFormatted = `${hours}:${minutes}`;

return {
  json: {
    response_text: `Cita confirmada para el ${fechaFormatted} a las ${horaFormatted}. Te esperamos en la clinica. Hasta pronto!`,
    new_state: 'awaiting_intent',
    new_context: JSON.stringify({ booking_step: 'complete' })
  }
};

// Collect response from whichever branch ran
const item = $input.item.json;
return {
  json: {
    response_text: item.response_text || 'Hubo un error. Por favor intenta de nuevo.',
    new_state: item.new_state || 'booking_flow',
    new_context: item.new_context || '{}'
  }
};
